// Build getUpdates params from wf47_polling_state_test rows (no token/chat in output).
const rows = $('Data Table - Load wf47 polling state').all().map((i) => i.json);
const byKey = (k) => {
  const row = rows.find((r) => r && r.key === k);
  return row ? row.value : null;
};
const lastUpdateId = Number(byKey('last_update_id') || 0);
const lastHandled = Number(byKey('last_handled_update_id') || 0);
let handledKeys = {};
try {
  const raw = byKey('handled_keys_json') || '{}';
  handledKeys = typeof raw === 'object' ? raw : JSON.parse(String(raw));
} catch {
  handledKeys = {};
}
return [{
  json: {
    offset: lastUpdateId,
    limit: 10,
    last_handled_update_id: lastHandled,
    handled_keys: handledKeys,
    open_decision_ids_test_only: ['D-9998-T'],
    state_table: 'wf47_polling_state_test',
    test_only: true
  }
}];

// Normalize — no raw chat_id/user_id/message body in output.
const build = $('Build getUpdates request from state').first().json;
const lastHandled = Number(build.last_handled_update_id || 0);
const resp = $input.item.json;
const body = resp && resp.body !== undefined ? resp.body : resp;
const results = body && Array.isArray(body.result) ? body.result : [];
const OPEN = build.open_decision_ids_test_only || ['D-9998-T'];
const items = [];
for (const u of results) {
  const cq = u.callback_query || {};
  const msg = cq.message || u.message || {};
  const text = String(cq.data || msg.text || '').trim();
  let inbound_kind = 'unknown';
  if (text.startsWith('note:')) inbound_kind = 'note';
  else if (text.startsWith('dp:')) inbound_kind = 'callback';
  else if (/^[123]$/.test(text)) inbound_kind = 'plain_option';
  const uid = u.update_id;
  items.push({
    update_id: uid,
    inbound_kind,
    inbound_text: text,
    stale_update_id_guard: uid != null && uid <= lastHandled
  });
}
return {
  json: {
    http_ok: body && body.ok === true,
    result_count: results.length,
    candidates: items,
    open_decision_ids: OPEN,
    last_handled_update_id: lastHandled,
    handled_keys: build.handled_keys,
    test_only: true
  }
};

// Allowed-chat — read Set node only (edit Set Wf47 UI config in n8n, not Code).
const d = $input.item.json;
const ui = $('Set Wf47 UI config').first().json;
const ALLOWED = String(ui.allowed_chat_id || '').trim();
const configured = ALLOWED.length > 0 && ALLOWED.indexOf('CONFIGURE') === -1 && ALLOWED.indexOf('**') === -1;
return {
  json: {
    ...d,
    allowed_chat_configured: configured,
    chat_filter_ok: configured,
    block_reason: configured ? null : 'allowed_chat_not_configured'
  }
};

// Parse Decision Packet — newest non-stale candidate.
const d = $input.item.json;
const OPEN = d.open_decision_ids || ['D-9998-T'];
const sorted = [...(d.candidates || [])].sort((a, b) => (b.update_id || 0) - (a.update_id || 0));
let best = null;
for (const c of sorted) {
  if (c.stale_update_id_guard) continue;
  let decision_id = null;
  let selected_option = null;
  let note_present = false;
  if (c.inbound_kind === 'callback') {
    const m = String(c.inbound_text).match(/^dp:(D-\d{4}-[A-Z]):([123])$/);
    if (m) { decision_id = m[1]; selected_option = m[2]; }
  } else if (c.inbound_kind === 'plain_option' && OPEN.length === 1) {
    decision_id = OPEN[0];
    selected_option = c.inbound_text;
  } else if (c.inbound_kind === 'note') {
    const nm = String(c.inbound_text).match(/^note:(D-\d{4}-[A-Z]):(.+)$/);
    if (nm) {
      decision_id = nm[1];
      note_present = true;
      selected_option = null;
    }
  }
  if (decision_id) {
    best = { update_id: c.update_id, inbound_kind: c.inbound_kind, decision_id, selected_option, note_present };
    break;
  }
}
return {
  json: {
    ...d,
    parsed: best,
    parse_ok: !!best
  }
};

// Idempotency using Data Table state (not staticData).
const d = $input.item.json;
const build = $('Build getUpdates request from state').first().json;
const lastHandled = Number(build.last_handled_update_id || 0);
let handledKeys = {};
try {
  const hk = build.handled_keys;
  handledKeys = typeof hk === 'object' && hk ? { ...hk } : JSON.parse(String(hk || '{}'));
} catch {
  handledKeys = {};
}
const p = d.parsed;
let status = 'blocked';
let duplicate_or_stale = false;
let block_reason = d.block_reason || 'no_matching_update';
let update_id = null;
let decision_id = null;
let selected_option = null;
let note_present = false;
let offset_after = Number(build.offset || 0);
let persist_state = null;
if (!d.chat_filter_ok) {
  block_reason = 'allowed_chat_not_configured';
} else if (!p) {
  block_reason = 'no_parseable_decision_response';
} else {
  update_id = p.update_id;
  decision_id = p.decision_id;
  selected_option = p.selected_option;
  note_present = !!p.note_present;
  const open = (d.open_decision_ids || []).includes(decision_id);
  const slot = selected_option || (note_present ? 'note' : 'unknown');
  const key = decision_id + ':' + slot + ':' + update_id;
  if (update_id != null && update_id <= lastHandled) {
    duplicate_or_stale = true;
    block_reason = 'stale_old_update_id';
  } else if (!open) {
    duplicate_or_stale = true;
    block_reason = 'stale_or_unknown_decision_id';
  } else if (handledKeys[key]) {
    duplicate_or_stale = true;
    block_reason = 'duplicate_or_double_click';
  } else if (p.inbound_kind === 'plain_option' || p.inbound_kind === 'callback') {
    handledKeys[key] = new Date().toISOString();
    offset_after = update_id + 1;
    status = 'accepted';
    block_reason = null;
    persist_state = {
      last_update_id: String(offset_after),
      last_handled_update_id: String(update_id),
      handled_keys_json: JSON.stringify(handledKeys)
    };
  } else if (note_present) {
    status = 'note_placeholder';
    block_reason = null;
  }
}
return {
  json: {
    status,
    decision_id,
    selected_option,
    update_id,
    duplicate_or_stale,
    note_present,
    block_reason,
    allowed_chat_configured: !!d.allowed_chat_configured,
    offset_after_placeholder: offset_after,
    last_handled_update_id: lastHandled,
    persist_state,
    test_only: true
  }
};

// Emit 3 Data Table upsert rows for accepted path only.
const g = $('Offset dedupe idempotency guard').first().json;
const p = g.persist_state;
if (!p) return [];
const note = 'wf47 polling state TEST ONLY';
return [
  { json: { state_key: 'last_update_id', state_value: p.last_update_id, note } },
  { json: { state_key: 'last_handled_update_id', state_value: p.last_handled_update_id, note } },
  { json: { state_key: 'handled_keys_json', state_value: p.handled_keys_json, note } }
];

// Sanitized receipt — no raw chat_id/user_id/token/message body.
const d = $('Offset dedupe idempotency guard').item.json;
return {
  json: {
    inspect_status: d.status,
    decision_id: d.decision_id,
    selected_option: d.selected_option,
    update_id: d.update_id,
    duplicate_or_stale: d.duplicate_or_stale,
    note_present: d.note_present,
    block_reason: d.block_reason,
    allowed_chat_configured: d.allowed_chat_configured,
    offset_after_placeholder: d.offset_after_placeholder,
    last_handled_update_id: d.last_handled_update_id,
    test_only: true
  }
};

// Read-only inspect — contract fields only.
const d = $input.item.json;
return {
  json: {
    inspect_status: d.inspect_status,
    decision_id: d.decision_id || null,
    selected_option: d.selected_option || null,
    update_id: d.update_id ?? null,
    duplicate_or_stale: d.duplicate_or_stale || false,
    note_present: d.note_present || false,
    block_reason: d.block_reason || null,
    allowed_chat_configured: d.allowed_chat_configured === true,
    offset_after_placeholder: d.offset_after_placeholder ?? null,
    last_handled_update_id: d.last_handled_update_id ?? null,
    test_only: true
  }
};
